import React from 'react';
import {Link} from 'react-router-dom';
export default function Header() {
  return(
  <header>
      <nav className="navbar navbar-expand-lg navbar-light primary-gradient shadow">
        <Link>
          <h5>MERN Stack Application</h5>
        </Link>
      </nav>
  </header>
  )
}
